#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct {
	int value;
} record;

typedef struct {
	int location;
	int indices[DEFAULT_ORDER + 1];
	int keys[DEFAULT_ORDER + 1];
	int is_leaf;
	int num_keys;
} knode;

__kernel void
kernel_cpu(	const long maxheight,
			__global knode *knodes,
			const long knodes_elem,
			__global record *records,
			__global long *currKnode,
			__global long *offset,
			__global int *keys,
			__global record *ans)
{
	size_t bid = get_group_id(0);
	size_t thid = get_local_id(0);
	size_t threadsPerBlock = get_local_size(0);

	if (bid >= get_num_groups(0)) return;

	for (int i = 0; i < maxheight; i++) {
		// Each thread examines one key slot
		if (thid < threadsPerBlock) {
			int key_left = knodes[currKnode[bid]].keys[thid];
			int key_right = knodes[currKnode[bid]].keys[thid + 1];
			int key_val = keys[bid];

			if (key_left <= key_val && key_right > key_val) {
				if (knodes[currKnode[bid]].indices[thid] < knodes_elem) {
					offset[bid] = knodes[currKnode[bid]].indices[thid];
				}
			}
		}
		barrier(CLK_LOCAL_MEM_FENCE | CLK_GLOBAL_MEM_FENCE);
		if (thid == 0) {
			currKnode[bid] = offset[bid];
		}
		barrier(CLK_LOCAL_MEM_FENCE | CLK_GLOBAL_MEM_FENCE);
	}

	if (thid < threadsPerBlock) {
		if (knodes[currKnode[bid]].keys[thid] == keys[bid]) {
			ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
		}
	}
}

