#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct {
	int location;
	int indices[DEFAULT_ORDER + 1];
	int keys[DEFAULT_ORDER + 1];
	int is_leaf;
	int num_keys;
} knode;

__kernel void
kernel_cpu_2(	const long maxheight,
				__global knode *knodes,
				const long knodes_elem,
				const int order,
				const int count,
				__global long *currKnode,
				__global long *offset,
				__global long *lastKnode,
				__global long *offset_2,
				__global int *start,
				__global int *end,
				__global int *recstart,
				__global int *reclength)
{
	size_t bid = get_global_id(0) / get_local_size(0);
	size_t thid = get_global_id(0) % get_local_size(0);
	size_t threadsPerBlock = get_local_size(0);

	if (bid >= count) return;

	for (int i = 0; i < maxheight; i++) {
		if (thid < threadsPerBlock) {
			int key_curr_left = knodes[currKnode[bid]].keys[thid];
			int key_curr_right = knodes[currKnode[bid]].keys[thid + 1];
			int key_start = start[bid];
			if (key_curr_left <= key_start && key_curr_right > key_start) {
				if (knodes[currKnode[bid]].indices[thid] < knodes_elem) {
					offset[bid] = knodes[currKnode[bid]].indices[thid];
				}
			}

			int key_last_left = knodes[lastKnode[bid]].keys[thid];
			int key_last_right = knodes[lastKnode[bid]].keys[thid + 1];
			int key_end = end[bid];
			if (key_last_left <= key_end && key_last_right > key_end) {
				if (knodes[lastKnode[bid]].indices[thid] < knodes_elem) {
					offset_2[bid] = knodes[lastKnode[bid]].indices[thid];
				}
			}
		}
		barrier(CLK_LOCAL_MEM_FENCE | CLK_GLOBAL_MEM_FENCE);
		if (thid == 0) {
			currKnode[bid] = offset[bid];
			lastKnode[bid] = offset_2[bid];
		}
		barrier(CLK_LOCAL_MEM_FENCE | CLK_GLOBAL_MEM_FENCE);
	}

	if (thid < threadsPerBlock) {
		if (knodes[currKnode[bid]].keys[thid] == start[bid]) {
			recstart[bid] = knodes[currKnode[bid]].indices[thid];
		}
	}

	if (thid < threadsPerBlock) {
		if (knodes[lastKnode[bid]].keys[thid] == end[bid]) {
			reclength[bid] = knodes[lastKnode[bid]].indices[thid] - recstart[bid] + 1;
		}
	}
}
